using System;
using System.Reflection;
using System.Linq;

var home = Environment.GetFolderPath(Environment.SpecialFolder.UserProfile);
var asm = Assembly.LoadFrom($"{home}/.nuget/packages/mstest.testframework/4.2.2/lib/net8.0/MSTest.TestFramework.dll");
var assertType = asm.GetType("Microsoft.VisualStudio.TestTools.UnitTesting.Assert");
var methods = assertType!.GetMethods(BindingFlags.Public | BindingFlags.Static)
    .Where(m => m.Name == "AreEqual" || m.Name == "AreNotEqual" || m.Name == "AreSame" || m.Name == "AreNotSame")
    .Select(m => {
        var ps = string.Join(", ", m.GetParameters().Select(p => p.ParameterType.ToString() + " " + p.Name));
        var genArgs = m.IsGenericMethod ? "<" + string.Join(",", m.GetGenericArguments().Select(g => g.Name)) + ">" : "";
        return m.Name + genArgs + "(" + ps + ")";
    });
foreach (var m in methods) Console.WriteLine(m);
ENDOFFILE
